#include "tcs3200.h"
#include "delay.h"
#include "usart.h"
#include "lcd.h"

float RGB_Scale[3];         
int count=0;              
int cnt[3];             
int flag=0; 

//S0-----PA4,S1-----PA5,S2-----PA6,S3-----PA7,LED-----PC5,OUT-----PA0

void TCS_GPIO_Init(void)
{

 GPIO_InitTypeDef  GPIO_InitStructure;

 RCC_APB2PeriphClockCmd(RCC_APB2Periph_GPIOA|RCC_APB2Periph_GPIOC, ENABLE);  

 GPIO_InitStructure.GPIO_Pin = GPIO_Pin_4|GPIO_Pin_5|GPIO_Pin_6|GPIO_Pin_7;     
 GPIO_InitStructure.GPIO_Mode = GPIO_Mode_Out_PP;   
 GPIO_InitStructure.GPIO_Speed = GPIO_Speed_50MHz;   
 GPIO_Init(GPIOA, &GPIO_InitStructure);     
 GPIO_SetBits(GPIOA,GPIO_Pin_5|GPIO_Pin_6|GPIO_Pin_4|GPIO_Pin_7);       //PA.4567 Êä³ö¸ß


 GPIO_InitStructure.GPIO_Pin = GPIO_Pin_5;      
 GPIO_Init(GPIOC, &GPIO_InitStructure);       
 GPIO_SetBits(GPIOC,GPIO_Pin_5);      
}

void filter(int s2,int s3) 
{
    if(s2==0&&s3==0){
   S2_L;S3_L;
  }
    if(s2==0&&s3==1){
    S2_L;S3_H;
  }
    if(s2==1&&s3==0){
   S2_H;S3_L;
  }
    if(s2==1&&s3==1){
    S2_H;S3_H;
  }   
}

void TSC_WB(int s2, int s3)
{
  count = 0;   
  flag ++;   
  filter(s2, s3); 
}

void TCS3200_Init(void)
{
    TCS_GPIO_Init(); //Initialize GPIO of TCS3200
    S2_L; 
    S3_L;
}

void TCS_Get_RGB(void)
{
    TSC_WB(0,0);        //red
    delay_us(5000);     
    cnt[0] = TIM_GetCounter(TIM3);
    TIM_SetCounter(TIM3,0);     

    TSC_WB(0,1);        //green
    delay_us(5000);     
    cnt[1] = TIM_GetCounter(TIM3);
    TIM_SetCounter(TIM3,0);      

    TSC_WB(1,0);        //blue
    delay_us(5000);     
    cnt[2] = TIM_GetCounter(TIM3);
    TIM_SetCounter(TIM3,0);     

    if(flag == 1)    
    {
        RGB_Scale[0] = 255.0/cnt[0];
        RGB_Scale[1] = 255.0/cnt[1];
        RGB_Scale[2] = 255.0/cnt[2];
    }

    USART_Printf(USART1,"RED:%.1f GREEN:%.1f BLUE:%.1f \r\n",RGB_Scale[0]*cnt[0],RGB_Scale[1]*cnt[1],RGB_Scale[2]*cnt[2]); //Output RGB data through USART
    LCD_ShowString(10,130,"RED: "); 
    LCD_ShowNum(70,130,(int)(RGB_Scale[0]*cnt[0]),3,16);  
    LCD_ShowString(10,150,"GREEN: "); 
    LCD_ShowNum(70,150,(int)(RGB_Scale[1]*cnt[1]),3,16);  
    LCD_ShowString(10,170,"BLUE: "); 
    LCD_ShowNum(70,170,(int)(RGB_Scale[2]*cnt[2]),3,16);  
}

